function Read-ProfileDefinition {
    param(
        [Parameter(Mandatory = $true)]
        [string]$ProfilePath
    )

    if (-not (Test-Path -LiteralPath $ProfilePath)) {
        throw "Experiment profile not found: $ProfilePath"
    }

